 1→import { ComponentChildren, ComponentType } from "preact";
 2→
 3→import { ScrollReader } from "./reader/ScrollReader.js";
 4→import { PaginatedReader } from "./reader/PaginatedReader.js";
 5→
 6→export type { ProgressData, ChapterMapData, OfflineProps } from "./reader/types.js";
 7→
 8→export interface ReaderProps {
 9→  children: ComponentChildren;
10→  title: string;
11→  bookTitle?: string;
12→  chapterSlug?: string;
13→  prevChapter?: { slug: string; title: string };
14→  nextChapter?: { slug: string; title: string };
15→  showDropCap?: boolean;
16→  paginationMode?: "scroll" | "paginated";
17→  onSaveProgress?: (data: import("./reader/types.js").ProgressData) => void;
18→  onRestoreProgress?: () => Promise<import("./reader/types.js").ProgressData | null>;
19→  bookProgressPercent?: number;
20→  initialContent?: ComponentType<{ components?: Record<string, unknown> }>;
21→  chapterMapData?: import("./reader/types.js").ChapterMapData;
22→  currentChapterSlug?: string;
23→  allChapters?: Array<{ slug: string; title: string; wordCount?: number }>;
24→  bookBasePath?: string;
25→  onChapterChange?: (slug: string, page: number, totalPages: number) => void;
26→  mdxComponents?: Record<string, unknown>;
27→  offlineProps?: import("./reader/types.js").OfflineProps;
28→}
29→
30→export function Reader({
31→  children,
32→  bookTitle,
33→  prevChapter,
34→  nextChapter,
35→  showDropCap = true,
36→  paginationMode = "scroll",
37→  onSaveProgress,
38→  onRestoreProgress,
39→  bookProgressPercent,
40→  initialContent,
41→  chapterMapData,
42→  currentChapterSlug,
43→  allChapters,
44→  bookBasePath,
45→  onChapterChange,
46→  mdxComponents,
47→  offlineProps,
48→}: ReaderProps) {
49→  if (paginationMode === "paginated") {
50→    return (
51→      <PaginatedReader
52→        bookTitle={bookTitle}
53→        prevChapter={prevChapter}
54→        nextChapter={nextChapter}
55→        showDropCap={showDropCap}
56→        onSaveProgress={onSaveProgress}
57→        onRestoreProgress={onRestoreProgress}
58→        bookProgressPercent={bookProgressPercent}
59→        initialContent={initialContent}
60→        chapterMapData={chapterMapData}
61→        currentChapterSlug={currentChapterSlug}
62→        allChapters={allChapters}
63→        bookBasePath={bookBasePath}
64→        onChapterChange={onChapterChange}
65→        mdxComponents={mdxComponents}
66→        offlineProps={offlineProps}
67→      >
68→        {children}
69→      </PaginatedReader>
70→    );
71→  }
72→
73→  return (
74→    <ScrollReader
75→      bookTitle={bookTitle}
76→      prevChapter={prevChapter}
77→      nextChapter={nextChapter}
78→      showDropCap={showDropCap}
79→      onSaveProgress={onSaveProgress}
80→      onRestoreProgress={onRestoreProgress}
81→      allChapters={allChapters}
82→      bookBasePath={bookBasePath}
83→      currentChapterSlug={currentChapterSlug}
84→      offlineProps={offlineProps}
85→    >
86→      {children}
87→    </ScrollReader>
88→  );
89→}
