 51→    51→export function PaginatedReader({
 52→    52→  children,
 53→    53→  bookTitle,
 54→    54→  prevChapter,
 55→    55→  nextChapter,
 56→    56→  showDropCap,
 57→    57→  onSaveProgress,
 58→    58→  onRestoreProgress,
 59→    59→  bookProgressPercent,
 60→    60→  initialContent,
 61→    61→  chapterMapData,
 62→    62→  currentChapterSlug,
 63→    63→  allChapters,
 64→    64→  bookBasePath,
 65→    65→  onChapterChange,
 66→    66→  mdxComponents,
 67→    67→  offlineProps,
 68→    68→}: PaginatedReaderProps) {
 69→    69→  const containerRef = useRef<HTMLDivElement>(null);
 70→    70→  const viewportRef = useRef<HTMLDivElement>(null);
 71→    71→  const articleRef = useRef<HTMLElement>(null);
 72→    72→  const [currentPage, setCurrentPage] = useState(0);
 73→    73→  const [totalPages, setTotalPages] = useState(1);
 74→    74→  const totalPagesRef = useRef(1);
 75→    75→  totalPagesRef.current = totalPages;
 76→    76→  const [pagesReady, setPagesReady] = useState(false);
 77→    77→  const hasRestoredRef = useRef(false);
 78→    78→  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 79→    79→  const skipTransitionRef = useRef(false);
 80→    80→
 81→    81→  // Detect ?page=last on initial render (backward chapter navigation)
 82→    82→  const wantsLastPageRef = useRef(
 83→    83→    typeof window !== "undefined" &&
 84→    84→      new URLSearchParams(window.location.search).get("page") === "last"
 85→    85→  );
 86→    86→  // Hide content until page position is resolved (prevents flash at page 0
 87→    87→  // before jumping to the saved page). Covers both ?page=last and normal restore.
 88→    88→  const [awaitingRestore, setAwaitingRestore] = useState(
 89→    89→    wantsLastPageRef.current || !!onRestoreProgress
 90→    90→  );
 91→    91→
 92→    92→  // Multi-chapter state
 93→    93→  const [loadedChapters, setLoadedChapters] = useState<LoadedChapter[]>([]);
 94→    94→  const [chapterRanges, setChapterRanges] = useState<ChapterPageRange[]>([]);
 95→    95→  const [activeChapterSlug, setActiveChapterSlug] = useState(
 96→    96→    currentChapterSlug || ""
 97→    97→  );
 98→    98→  const preloadingRef = useRef<Set<string>>(new Set());
 99→    99→
100→   100→  // Whether we're in multi-chapter mode
101→   101→  const isMultiChapter = !!(
102→   102→    chapterMapData &&
103→   103→    initialContent &&
104→   104→    currentChapterSlug &&
105→   105→    allChapters
106→   106→  );
107→   107→
108→   108→  // Initialize loaded chapters
109→   109→  useEffect(() => {
110→   110→    if (isMultiChapter && initialContent && currentChapterSlug) {
111→   111→      const chapterInfo = allChapters!.find(
112→   112→        (ch) => ch.slug === currentChapterSlug
113→   113→      );
114→   114→      setLoadedChapters([
115→   115→        {
116→   116→          slug: currentChapterSlug,
117→   117→          title: chapterInfo?.title || currentChapterSlug,
118→   118→          Content: initialContent,
119→   119→        },
120→   120→      ]);
121→   121→      setActiveChapterSlug(currentChapterSlug);
122→   122→    }
123→   123→  }, []); // Only on mount
124→   124→
125→   125→  // Clean up ?page=last from the URL on mount
126→   126→  useEffect(() => {
127→   127→    if (wantsLastPageRef.current) {
128→   128→      const url = new URL(window.location.href);
129→   129→      url.searchParams.delete("page");
130→   130→      history.replaceState(null, "", url.pathname);
131→   131→    }
132→   132→  }, []);
133→   133→
134→   134→  // Settings & TOC panel state
135→   135→  const [settingsOpen, setSettingsOpen] = useState(false);
136→   136→  const [tocOpen, setTocOpen] = useState(false);
137→   137→  const [activeTheme, setActiveTheme] = useState<string>(() => {
138→   138→    if (typeof localStorage !== "undefined") {
139→   139→      return localStorage.getItem("pressy-theme") || "light";
140→   140→    }
141→   141→    return "light";
142→   142→  });
143→   143→  const [fontScale, setFontScale] = useState<number>(() => {
144→   144→    if (typeof localStorage !== "undefined") {
145→   145→      const saved = localStorage.getItem("pressy-font-size");
146→   146→      return saved ? parseFloat(saved) : 1.0;
147→   147→    }
148→   148→    return 1.0;
149→   149→  });
150→   150→
151→   151→  const applyFontScale = useCallback((scale: number) => {
152→   152→    if (scale === 1.0) {
153→   153→      document.documentElement.style.removeProperty("--font-size-base");
154→   154→    } else {
155→   155→      document.documentElement.style.setProperty(
156→   156→        "--font-size-base",
157→   157→        `calc(clamp(1rem, 0.875rem + 0.5vw, 1.25rem) * ${scale})`
158→   158→      );
159→   159→    }
160→   160→  }, []);
161→   161→
162→   162→  // Apply saved font scale on mount
163→   163→  useEffect(() => {
164→   164→    if (fontScale !== 1.0) {
165→   165→      applyFontScale(fontScale);
166→   166→    }
167→   167→  }, []);
168→   168→
169→   169→  // Sync real viewport height to CSS custom property.
170→   170→  // 100dvh is unreliable on Android PWAs where the system nav bar
171→   171→  // overlaps the content. window.innerHeight always reflects the
172→   172→  // actual usable area.
173→   173→  useEffect(() => {
174→   174→    const container = containerRef.current;
175→   175→    if (!container) return;
176→   176→
177→   177→    const syncHeight = () => {
178→   178→      container.style.setProperty("--app-height", `${window.innerHeight}px`);
179→   179→    };
180→   180→    syncHeight();
181→   181→
182→   182→    window.addEventListener("resize", syncHeight);
183→   183→    window.visualViewport?.addEventListener("resize", syncHeight);
184→   184→    return () => {
185→   185→      window.removeEventListener("resize", syncHeight);
186→   186→      window.visualViewport?.removeEventListener("resize", syncHeight);
187→   187→    };
188→   188→  }, []);
189→   189→
190→   190→  const handleThemeChange = useCallback((theme: string) => {
191→   191→    setActiveTheme(theme);
192→   192→    localStorage.setItem("pressy-theme", theme);
193→   193→    const resolved =
194→   194→      theme === "system"
195→   195→        ? window.matchMedia("(prefers-color-scheme: dark)").matches
196→   196→          ? "dark"
197→   197→          : "light"
198→   198→        : theme;
199→   199→    document.documentElement.setAttribute("data-theme", resolved);
200→   200→  }, []);
201→   201→
202→   202→  // Drag/swipe state
203→   203→  const [isDragging, setIsDragging] = useState(false);
204→   204→  const [dragOffset, setDragOffset] = useState(0);
205→   205→  const [chapterHint, setChapterHint] = useState<"next" | "prev" | null>(null);
206→   206→
