  1→import { signal } from '@preact/signals'
  2→
  3→const CACHED_BOOKS_KEY = 'pressy-cached-books'
  4→
  5→export const offlineStatus = signal<'online' | 'offline'>('online')
  6→export const cacheProgress = signal<{ bookSlug: string; current: number; total: number } | null>(null)
  7→export const swReady = signal<boolean>(false)
  8→export const installPrompt = signal<Event | null>(null)
  9→
 10→// Restore cached books from localStorage synchronously on load
 11→function loadCachedBooks(): Set<string> {
 12→  if (typeof localStorage === 'undefined') return new Set()
 13→  try {
 14→    const stored = localStorage.getItem(CACHED_BOOKS_KEY)
 15→    if (stored) return new Set(JSON.parse(stored))
 16→  } catch {}
 17→  return new Set()
 18→}
 19→
 20→export const cachedBooks = signal<Set<string>>(loadCachedBooks())
 21→
 22→// Initialize offline detection
 23→if (typeof window !== 'undefined') {
 24→  offlineStatus.value = navigator.onLine ? 'online' : 'offline'
 25→
 26→  window.addEventListener('online', () => {
 27→    offlineStatus.value = 'online'
 28→  })
 29→
 30→  window.addEventListener('offline', () => {
 31→    offlineStatus.value = 'offline'
 32→  })
 33→}
 34→
 35→// PWA install prompt
 36→export function setupInstallPrompt(): void {
 37→  window.addEventListener('beforeinstallprompt', (e) => {
 38→    e.preventDefault()
 39→    installPrompt.value = e
 40→  })
 41→  window.addEventListener('appinstalled', () => {
 42→    installPrompt.value = null
 43→  })
 44→}
 45→
 46→export async function triggerInstall(): Promise<boolean> {
 47→  const prompt = installPrompt.value as any
 48→  if (!prompt) return false
 49→  prompt.prompt()
 50→  const { outcome } = await prompt.userChoice
 51→  installPrompt.value = null
 52→  return outcome === 'accepted'
 53→}
 54→
 55→// Service Worker registration
 56→export async function registerServiceWorker(basePath = ''): Promise<ServiceWorkerRegistration | null> {
 57→  if (!('serviceWorker' in navigator)) {
 58→    console.warn('Service workers are not supported')
 59→    return null
 60→  }
 61→
 62→  const swUrl = basePath ? `${basePath}/sw.js` : '/sw.js'
 63→  const scope = basePath ? `${basePath}/` : '/'
 64→
 65→  try {
 66→    const registration = await navigator.serviceWorker.register(swUrl, {
 67→      scope,
 68→    })
 69→
 70→    // Listen for messages from service worker
 71→    navigator.serviceWorker.addEventListener('message', handleSWMessage)
 72→
 73→    // Mark SW as ready when controller is available
 74→    if (navigator.serviceWorker.controller) {
 75→      swReady.value = true
 76→    } else {
 77→      navigator.serviceWorker.addEventListener('controllerchange', () => {
 78→        swReady.value = true
 79→      })
 80→    }
 81→
 82→    // Handle updates
 83→    registration.addEventListener('updatefound', () => {
 84→      const newWorker = registration.installing
 85→      if (!newWorker) return
 86→
 87→      newWorker.addEventListener('statechange', () => {
 88→        if (newWorker.state === 'activated') {
 89→          swReady.value = true
 90→        }
 91→      })
 92→    })
 93→
 94→    return registration
 95→  } catch (err) {
 96→    console.error('Service worker registration failed:', err)
 97→    return null
 98→  }
 99→}
100→
101→function persistCachedBooks() {
102→  try {
103→    localStorage.setItem(CACHED_BOOKS_KEY, JSON.stringify([...cachedBooks.value]))
104→  } catch {}
105→}
106→
107→function handleSWMessage(event: MessageEvent) {
108→  const { type } = event.data
109→
110→  if (type === 'CACHE_PROGRESS') {
111→    const { bookSlug, current, total } = event.data
112→    cacheProgress.value = { bookSlug, current, total }
113→  }
114→
115→  if (type === 'CACHE_COMPLETE') {
116→    const { bookSlug } = event.data
117→    cacheProgress.value = null
118→    const newCached = new Set(cachedBooks.value)
119→    newCached.add(bookSlug)
120→    cachedBooks.value = newCached
121→    persistCachedBooks()
122→  }
123→
124→  if (type === 'CACHE_STATUS') {
125→    const { cached } = event.data as { cached: string[] }
126→    const newCached = new Set<string>()
127→    for (const url of cached) {
128→      const match = url.match(/\/books\/([^/]+)/)
129→      if (match) {
130→        newCached.add(match[1])
131→      }
132→    }
133→    cachedBooks.value = newCached
134→    persistCachedBooks()
135→  }
136→
137→  if (type === 'CACHE_CLEARED') {
138→    const { bookSlug } = event.data
139→    const newCached = new Set(cachedBooks.value)
140→    newCached.delete(bookSlug)
141→    cachedBooks.value = newCached
142→    persistCachedBooks()
143→  }
144→}
145→
146→// Download a book for offline reading
147→export async function downloadBookForOffline(
148→  bookSlug: string,
149→  chapterUrls: string[]
150→): Promise<boolean> {
151→  if (!('serviceWorker' in navigator) || !navigator.serviceWorker.controller) {
152→    console.warn('Service worker not available')
153→    return false
154→  }
155→
156→  // Build full URLs
157→  const urls = chapterUrls.map((url) =>
158→    url.startsWith('http') ? url : `${window.location.origin}${url}`
159→  )
160→
161→  cacheProgress.value = { bookSlug, current: 0, total: urls.length }
162→
163→  // Optimistically persist to localStorage immediately so state survives refresh
164→  const newCached = new Set(cachedBooks.value)
165→  newCached.add(bookSlug)
166→  cachedBooks.value = newCached
167→  persistCachedBooks()
168→
169→  // Send message to service worker
170→  navigator.serviceWorker.controller.postMessage({
171→    type: 'CACHE_BOOK',
172→    bookSlug,
173→    urls,
174→  })
175→
176→  return true
177→}
178→
179→// Check if a book is available offline
180→export function isBookCached(bookSlug: string): boolean {
181→  return cachedBooks.value.has(bookSlug)
182→}
183→
184→// Get cache status for URLs
185→export async function checkCacheStatus(urls: string[]): Promise<void> {
186→  if (!('serviceWorker' in navigator) || !navigator.serviceWorker.controller) {
187→    return
188→  }
189→
190→  navigator.serviceWorker.controller.postMessage({
191→    type: 'GET_CACHE_STATUS',
192→    urls: urls.map((url) =>
193→      url.startsWith('http') ? url : `${window.location.origin}${url}`
194→    ),
195→  })
196→}
197→
198→// Clear cached book
199→export async function clearBookCache(bookSlug: string): Promise<boolean> {
200→  // Update state and persist immediately
201→  const newCached = new Set(cachedBooks.value)
202→  newCached.delete(bookSlug)
203→  cachedBooks.value = newCached
204→  persistCachedBooks()
205→
206→  if (!('serviceWorker' in navigator) || !navigator.serviceWorker.controller) {
207→    // Fallback to direct cache API
208→    try {
209→      const cache = await caches.open('pressy-offline-books')
210→      const keys = await cache.keys()
211→
212→      for (const request of keys) {
213→        if (request.url.includes(`/books/${bookSlug}`)) {
214→          await cache.delete(request)
215→        }
216→      }
217→
218→      return true
219→    } catch (err) {
220→      console.error('Failed to clear cache:', err)
221→      return false
222→    }
223→  }
224→
225→  // Prefer message-based approach so SW can coordinate
226→  navigator.serviceWorker.controller.postMessage({
227→    type: 'CLEAR_BOOK_CACHE',
228→    bookSlug,
229→  })
230→  return true
231→}
