334→              <a
335→                href={bookBasePath ? bookBasePath.replace(/\/books\/[^/]+$/, '') || '/' : '/'}
336→                class="pressy-toc-item pressy-toc-item--home"
337→                onClick={() => setTocOpen(false)}
338→              >
339→                <span class="pressy-toc-item-num">
340→                  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14">
